$(document).ready(function(){$(document).on("change","#division_id",function(a){$(this).val()&&$.ajax({url:BASE_URL+"/addresses/district/get",method:"get",data:{division_id:$(this).val()},dataType:"json",success:function(t){t!=""?($("#district_id").empty(),$("#district_id").html(t)):notify("No District Found !!","danger")}})}),$(document).on("change","#district_id",function(a){$(this).val()&&$.ajax({url:BASE_URL+"/addresses/thana/get",method:"get",data:{district_id:$(this).val()},dataType:"json",success:function(t){t!=""?($("#thana_id").empty(),$("#thana_id").html(t)):notify("No Thana Found !!","danger")}})}),$(document).on("change","#thana_id",function(a){$(this).val()&&$.ajax({url:BASE_URL+"/addresses/area/get",method:"get",data:{thana_id:$(this).val()},dataType:"json",success:function(t){t!=""?($("#area_id").empty(),$("#area_id").html(t)):notify("No Area Found !!","danger")}})})});
